   213→    @Override
   214→    public void processBarrier(
   215→            CheckpointBarrier barrier, InputChannelInfo channelInfo, boolean isRpcTriggered)
   216→            throws IOException {
   217→        long barrierId = barrier.getId();
   218→        LOG.debug("{}: Received barrier from channel {} @ {}.", taskName, channelInfo, barrierId);
   219→
   220→        if (currentCheckpointId > barrierId
   221→                || (currentCheckpointId == barrierId && !isCheckpointPending())) {
   222→            if (!barrier.getCheckpointOptions().isUnalignedCheckpoint()) {
   223→                inputs[channelInfo.getGateIdx()].resumeConsumption(channelInfo);
   224→            }
   225→            return;
   226→        }
   227→
   228→        checkNewCheckpoint(barrier);
   229→        checkState(currentCheckpointId == barrierId);
   230→
   231→        markCheckpointAlignedAndTransformState(
   232→                channelInfo,
   233→                barrier,
   234→                state -> state.barrierReceived(context, channelInfo, barrier, !isRpcTriggered));
   235→    }
   236→
   237→    protected void markCheckpointAlignedAndTransformState(
   238→            InputChannelInfo alignedChannel,
   239→            CheckpointBarrier barrier,
   240→            FunctionWithException<BarrierHandlerState, BarrierHandlerState, Exception>
   241→                    stateTransformer)
   242→            throws IOException {
   243→
   244→        alignedChannels.add(alignedChannel);
   245→        if (alignedChannels.size() == 1) {
   246→            if (targetChannelCount == 1) {
   247→                markAlignmentStartAndEnd(barrier.getId(), barrier.getTimestamp());
   248→            } else {
   249→                markAlignmentStart(barrier.getId(), barrier.getTimestamp());
   250→            }
   251→        }
   252→
   253→        // we must mark alignment end before calling currentState.barrierReceived which might
   254→        // trigger a checkpoint with unfinished future for alignment duration
   255→        if (alignedChannels.size() == targetChannelCount) {
   256→            if (targetChannelCount > 1) {
   257→                markAlignmentEnd();
   258→            }
   259→        }
   260→
   261→        try {
   262→            currentState = stateTransformer.apply(currentState);
   263→        } catch (CheckpointException e) {
   264→            abortInternal(currentCheckpointId, e);
   265→        } catch (Exception e) {
   266→            ExceptionUtils.rethrowIOException(e);
   267→        }
   268→
   269→        if (alignedChannels.size() == targetChannelCount) {
   270→            alignedChannels.clear();
   271→            lastCancelledOrCompletedCheckpointId = currentCheckpointId;
   272→            LOG.debug(
   273→                    "{}: All the channels are aligned for checkpoint {}.",
   274→                    taskName,
   275→                    currentCheckpointId);
   276→            resetAlignmentTimer();
   277→            allBarriersReceivedFuture.complete(null);
   278→        }
   279→    }
