   290→    @Override
   291→    public void processBarrierAnnouncement(
   292→            CheckpointBarrier announcedBarrier, int sequenceNumber, InputChannelInfo channelInfo)
   293→            throws IOException {
   294→        checkNewCheckpoint(announcedBarrier);
   295→
   296→        long barrierId = announcedBarrier.getId();
   297→        if (currentCheckpointId > barrierId
   298→                || (currentCheckpointId == barrierId && !isCheckpointPending())) {
