   300→                    "{}: Obsolete announcement of checkpoint {} for channel {}.",
   301→                    taskName,
   302→                    barrierId,
   303→                    channelInfo);
   304→            return;
   305→        }
   306→
   307→        currentState = currentState.announcementReceived(context, channelInfo, sequenceNumber);
