   310→    private void registerAlignmentTimer(CheckpointBarrier announcedBarrier) {
   311→        long timerDelay = BarrierAlignmentUtil.getTimerDelay(getClock(), announcedBarrier);
   312→
   313→        this.currentAlignmentTimer =
   314→                registerTimer.registerTask(
   315→                        () -> {
   316→                            long barrierId = announcedBarrier.getId();
   317→                            try {
   318→                                if (currentCheckpointId == barrierId
   319→                                        && !getAllBarriersReceivedFuture(barrierId).isDone()) {
   320→                                    currentState =
   321→                                            currentState.alignedCheckpointTimeout(
   322→                                                    context, announcedBarrier);
   323→                                }
   324→                            } catch (CheckpointException ex) {
   325→                                this.abortInternal(barrierId, ex);
   326→                            } catch (Exception e) {
   327→                                ExceptionUtils.rethrowIOException(e);
   328→                            }
   329→                            currentAlignmentTimer = null;
   330→                            return null;
   331→                        },
   332→                        Duration.ofMillis(timerDelay));
   333→    }
