   335→    private void checkNewCheckpoint(CheckpointBarrier barrier) throws IOException {
   336→        long barrierId = barrier.getId();
   337→        if (currentCheckpointId >= barrierId) {
   338→            return; // This barrier is not the first for this checkpoint.
   339→        }
   340→
   341→        if (isCheckpointPending()) {
   342→            cancelSubsumedCheckpoint(barrierId);
   343→        }
   344→        currentCheckpointId = barrierId;
   345→        pendingCheckpointBarrier = barrier;
   346→        alignedChannels.clear();
   347→        targetChannelCount = numOpenChannels;
   348→        allBarriersReceivedFuture = new CompletableFuture<>();
   349→
   350→        if (alternating && barrier.getCheckpointOptions().isTimeoutable()) {
   351→            registerAlignmentTimer(barrier);
   352→        }
   353→    }
