   355→    @Override
   356→    public void processCancellationBarrier(
   357→            CancelCheckpointMarker cancelBarrier, InputChannelInfo channelInfo) throws IOException {
   358→        final long cancelledId = cancelBarrier.getCheckpointId();
   359→        if (cancelledId > currentCheckpointId
   360→                || (cancelledId == currentCheckpointId && alignedChannels.size() > 0)) {
   361→            LOG.debug("{}: Received cancellation {}.", taskName, cancelledId);
   362→            abortInternal(
   363→                    cancelledId,
   364→                    new CheckpointException(
   365→                            CheckpointFailureReason.CHECKPOINT_DECLINED_ON_CANCELLATION_BARRIER));
