   374→    private void abortInternal(long cancelledId, CheckpointException exception) throws IOException {
   375→        LOG.debug(
   376→                "{}: Aborting checkpoint {} after exception {}.",
   377→                taskName,
   378→                currentCheckpointId,
   379→                exception);
   380→        // by setting the currentCheckpointId to this checkpoint while keeping the numBarriers
   381→        // at zero means that no checkpoint barrier can start a new alignment
   382→        currentCheckpointId = Math.max(cancelledId, currentCheckpointId);
   383→        lastCancelledOrCompletedCheckpointId =
   384→                Math.max(lastCancelledOrCompletedCheckpointId, cancelledId);
   385→        pendingCheckpointBarrier = null;
   386→        alignedChannels.clear();
   387→        targetChannelCount = 0;
   388→        resetAlignmentTimer();
   389→        currentState = currentState.abort(cancelledId);
   390→        if (cancelledId == currentCheckpointId) {
   391→            resetAlignment();
   392→        }
   393→        notifyAbort(cancelledId, exception);
   394→        allBarriersReceivedFuture.completeExceptionally(exception);
   395→    }
