   404→    @Override
   405→    public void processEndOfPartition(InputChannelInfo channelInfo) throws IOException {
   406→        numOpenChannels--;
   407→
   408→        if (!isCheckpointAfterTasksFinishedEnabled()) {
   409→            if (isCheckpointPending()) {
   410→                LOG.warn(
