   432→
   433→    @Override
   434→    public long getLatestCheckpointId() {
   435→        return currentCheckpointId;
   436→    }
   437→
   438→    @Override
   439→    public void close() throws IOException {
   440→        resetAlignmentTimer();
   441→        allBarriersReceivedFuture.cancel(false);
