   170→    @Override
   171→    public void processCancellationBarrier(
   172→            CancelCheckpointMarker cancelBarrier, InputChannelInfo channelInfo) throws IOException {
   173→        final long checkpointId = cancelBarrier.getCheckpointId();
   174→
   175→        if (LOG.isDebugEnabled()) {
   176→            LOG.debug("Received cancellation barrier for checkpoint {}", checkpointId);
   177→        }
   178→
   179→        // fast path for single channel trackers. We only go with the fast path
   180→        // for new checkpoints, otherwise we might met with the case that
   181→        // 1. Received barrier from channel 0 (2 in total) and start a new checkpoint.
   182→        // 2. Received EndOfPartition from channel 0.
   183→        // 3. Received cancellation barrier from channel 1.
   184→        // In this case we should cleanup the existing pending checkpoint.
   185→        if (cancelBarrier.getCheckpointId() > latestPendingCheckpointID && numOpenChannels == 1) {
   186→            resetAlignment();
   187→            notifyAbortOnCancellationBarrier(checkpointId);
   188→            return;
   189→        }
   190→
   191→        // -- general path for multiple input channels --
   192→
   193→        // find the checkpoint barrier in the queue of pending barriers
   194→        // while doing this we "abort" all checkpoints before that one
   195→        CheckpointBarrierCount cbc;
   196→        while ((cbc = pendingCheckpoints.peekFirst()) != null
   197→                && cbc.checkpointId() < checkpointId) {
   198→            pendingCheckpoints.removeFirst();
   199→
   200→            if (cbc.markAborted()) {
   201→                // abort the subsumed checkpoints if not already done
   202→                notifyAbortOnCancellationBarrier(cbc.checkpointId());
   203→            }
   204→        }
   205→
   206→        if (cbc != null && cbc.checkpointId() == checkpointId) {
   207→            // make sure the checkpoint is remembered as aborted
   208→            if (cbc.markAborted()) {
   209→                // this was the first time the checkpoint was aborted - notify
   210→                notifyAbortOnCancellationBarrier(checkpointId);
   211→            }
   212→
   213→            // we still count the barriers to be able to remove the entry once all barriers have
   214→            // been seen
   215→            if (cbc.markChannelAligned(channelInfo) == cbc.getTargetChannelCount()) {
   216→                // we can remove this entry
   217→                pendingCheckpoints.removeFirst();
   218→            }
   219→        } else if (checkpointId > latestPendingCheckpointID) {
   220→            notifyAbortOnCancellationBarrier(checkpointId);
   221→
   222→            latestPendingCheckpointID = checkpointId;
   223→
   224→            CheckpointBarrierCount abortedMarker =
   225→                    new CheckpointBarrierCount(
   226→                            cancelBarrier.getCheckpointId(), channelInfo, numOpenChannels);
   227→            abortedMarker.markAborted();
   228→            pendingCheckpoints.addFirst(abortedMarker);
   229→
   230→            // we have removed all other pending checkpoint barrier counts --> no need to check that
   231→            // we don't exceed the maximum checkpoints to track
   232→        } else {
   233→            // trailing cancellation barrier which was already cancelled
   234→        }
   235→    }
   236→
   237→    @Override
   238→    public void processEndOfPartition(InputChannelInfo channelInfo) throws IOException {
   239→        numOpenChannels--;
   240→
   241→        if (!isCheckpointAfterTasksFinishedEnabled()) {
   242→            while (!pendingCheckpoints.isEmpty()) {
   243→                CheckpointBarrierCount barrierCount = pendingCheckpoints.removeFirst();
   244→                if (barrierCount.markAborted()) {
   245→                    notifyAbort(
   246→                            barrierCount.checkpointId(),
   247→                            new CheckpointException(
   248→                                    CheckpointFailureReason
   249→                                            .CHECKPOINT_DECLINED_INPUT_END_OF_STREAM));
   250→                }
   251→            }
   252→            resetAlignment();
   253→        } else {
   254→            checkAlignmentOnEndOfPartitionIfEnabled(channelInfo);
   255→        }
   256→    }
   257→
   258→    private void checkAlignmentOnEndOfPartitionIfEnabled(InputChannelInfo channelInfo)
   259→            throws IOException {
   260→        // Finds the latest pending checkpoints that only waits for this channel.
   261→        CheckpointBarrierCount barrierCount = null;
   262→        int pos = pendingCheckpoints.size();
   263→
   264→        Iterator<CheckpointBarrierCount> reverseCheckpointIterator =
   265→                pendingCheckpoints.descendingIterator();
   266→        while (reverseCheckpointIterator.hasNext()) {
   267→            CheckpointBarrierCount next = reverseCheckpointIterator.next();
   268→            pos--;
   269→
   270→            if (next.markChannelAligned(channelInfo) == next.getTargetChannelCount()) {
   271→                barrierCount = next;
   272→                break;
   273→            }
   274→        }
   275→
   276→        if (barrierCount != null) {
   277→            for (int i = 0; i <= pos; i++) {
   278→                pendingCheckpoints.pollFirst();
   279→            }
   280→
   281→            if (!barrierCount.isAborted()) {
   282→                triggerCheckpointOnAligned(barrierCount);
   283→            }
   284→        }
   285→    }
   286→
   287→    private void triggerCheckpointOnAligned(CheckpointBarrierCount barrierCount)
   288→            throws IOException {
   289→        if (LOG.isDebugEnabled()) {
   290→            LOG.debug(
   291→                    "All the channels are aligned for checkpoint {}", barrierCount.checkpointId());
   292→        }
   293→
   294→        // Only one calculation of the alignment time at once is supported right now.
   295→        if (barrierCount.checkpointId == latestPendingCheckpointID) {
   296→            markAlignmentEnd();
   297→        }
   298→        checkState(
   299→                barrierCount.getPendingCheckpoint() != null,
   300→                "Pending checkpoint barrier must" + "exists for non-aborted checkpoints.");
   301→        notifyCheckpoint(barrierCount.getPendingCheckpoint());
   302→    }
   303→
   304→    public long getLatestCheckpointId() {
   305→        return pendingCheckpoints.isEmpty() ? -1 : pendingCheckpoints.peekLast().checkpointId();
   306→    }
   307→
   308→    public boolean isCheckpointPending() {
   309→        return !pendingCheckpoints.isEmpty();
   310→    }
   311→
   312→    @VisibleForTesting
   313→    int getNumOpenChannels() {
   314→        return numOpenChannels;
   315→    }
   316→
   317→    @VisibleForTesting
   318→    List<Long> getPendingCheckpointIds() {
   319→        return pendingCheckpoints.stream()
   320→                .map(CheckpointBarrierCount::checkpointId)
   321→                .collect(Collectors.toList());
   322→    }
   323→
   324→    /** Simple class for a checkpoint ID with a barrier counter. */
   325→    private static final class CheckpointBarrierCount {
   326→
   327→        private final long checkpointId;
   328→
   329→        private final int targetChannelCount;
   330→
   331→        private final Set<InputChannelInfo> alignedChannels = new HashSet<>();
   332→
   333→        @Nullable private final CheckpointBarrier pendingCheckpoint;
   334→
   335→        private boolean aborted;
   336→
   337→        CheckpointBarrierCount(
   338→                CheckpointBarrier pendingCheckpoint,
   339→                InputChannelInfo channelInfo,
   340→                int targetChannelCount) {
   341→            checkNotNull(pendingCheckpoint);
   342→            this.checkpointId = pendingCheckpoint.getId();
   343→            this.pendingCheckpoint = pendingCheckpoint;
   344→            alignedChannels.add(channelInfo);
   345→            this.targetChannelCount = targetChannelCount;
   346→        }
   347→
   348→        CheckpointBarrierCount(
   349→                long checkpointId, InputChannelInfo channelInfo, int targetChannelCount) {
   350→            this.checkpointId = checkpointId;
   351→            this.pendingCheckpoint = null;
   352→            alignedChannels.add(channelInfo);
   353→            this.targetChannelCount = targetChannelCount;
   354→        }
   355→
   356→        public long checkpointId() {
   357→            return checkpointId;
   358→        }
   359→
   360→        @Nullable
   361→        public CheckpointBarrier getPendingCheckpoint() {
   362→            return pendingCheckpoint;
   363→        }
   364→
   365→        public int getTargetChannelCount() {
   366→            return targetChannelCount;
   367→        }
   368→
   369→        public int markChannelAligned(InputChannelInfo inputChannelInfo) {
   370→            alignedChannels.add(inputChannelInfo);
   371→            return alignedChannels.size();
   372→        }
   373→
   374→        public boolean isAborted() {
   375→            return aborted;
   376→        }
   377→
   378→        public boolean markAborted() {
   379→            boolean firstAbort = !this.aborted;
   380→            this.aborted = true;
   381→            return firstAbort;
   382→        }
   383→
   384→        @Override
   385→        public String toString() {
   386→            return isAborted()
   387→                    ? String.format("checkpointID=%d - ABORTED", checkpointId)
   388→                    : String.format(
   389→                            "checkpointID=%d, count=%d, targetChannelCount=%d",
   390→                            checkpointId, alignedChannels.size(), targetChannelCount);
   391→        }
   392→    }
