   100→    /**
   101→     * Eagerly pulls and processes all priority events. Must be called from task thread.
   102→     *
   103→     * <p>Basic assumption is that no priority event needs to be handled by the {@link
   104→     * StreamTaskNetworkInput}.
   105→     */
   106→    private void processPriorityEvents() throws IOException, InterruptedException {
   107→        // check if the priority event is still not processed (could have been pulled before mail
   108→        // was being executed)
   109→        boolean hasPriorityEvent = inputGate.getPriorityEventAvailableFuture().isDone();
   110→        while (hasPriorityEvent) {
   111→            // process as many priority events as possible
   112→            final Optional<BufferOrEvent> bufferOrEventOpt = pollNext();
   113→            if (!bufferOrEventOpt.isPresent()) {
   114→                break;
