   125→    private void waitForPriorityEvents(InputGate inputGate, MailboxExecutor mailboxExecutor) {
   126→        final CompletableFuture<?> priorityEventAvailableFuture =
   127→                inputGate.getPriorityEventAvailableFuture();
   128→        assertNoException(
   129→                priorityEventAvailableFuture.thenRun(
   130→                        () -> {
   131→                            try {
   132→                                mailboxExecutor.execute(
   133→                                        MailboxExecutor.MailOptions.urgent(),
   134→                                        this::processPriorityEvents,
   135→                                        "process priority event @ gate %s",
   136→                                        inputGate);
   137→                            } catch (RejectedExecutionException ex) {
   138→                                LOG.debug(
   139→                                        "Ignored RejectedExecutionException in CheckpointedInputGate.waitForPriorityEvents");
   140→                            }
   141→                        }));
   142→    }
